Express is still the most popular Node.js framework in 2025 — and for good reason. It's minimal, flexible, and has a massive ecosystem. Here's how to build a production-ready REST API from scratch.

## Project Setup

```bash
mkdir my-api && cd my-api
npm init -y
npm install express cors helmet morgan dotenv express-validator
npm install -D nodemon
```

Update `package.json`:

```json
{
  "type": "module",
  "scripts": {
    "dev": "nodemon src/index.js",
    "start": "node src/index.js"
  }
}
```

## Project Structure

```
src/
  routes/
    users.js
    posts.js
  middleware/
    auth.js
    errorHandler.js
    validate.js
  controllers/
    usersController.js
  index.js
```

## Main Entry Point

```javascript
// src/index.js
import express from 'express'
import cors from 'cors'
import helmet from 'helmet'
import morgan from 'morgan'
import 'dotenv/config'
import usersRouter from './routes/users.js'
import { errorHandler } from './middleware/errorHandler.js'

const app = express()

// Security middleware
app.use(helmet())
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || '*' }))

// Logging
app.use(morgan('dev'))

// Body parsing
app.use(express.json({ limit: '10mb' }))

// Routes
app.use('/api/users', usersRouter)

// Health check
app.get('/health', (req, res) => res.json({ status: 'ok' }))

// 404 handler
app.use((req, res) => res.status(404).json({ error: 'Not found' }))

// Error handler (must be last)
app.use(errorHandler)

const PORT = process.env.PORT || 3000
app.listen(PORT, () => console.log(`API running on port ${PORT}`))
```

## Error Handler Middleware

```javascript
// src/middleware/errorHandler.js
export function errorHandler(err, req, res, next) {
  console.error(err.stack)

  const status = err.status || 500
  const message = err.message || 'Internal server error'

  res.status(status).json({
    error: message,
    ...(process.env.NODE_ENV === 'development' && { stack: err.stack })
  })
}

// Helper to create HTTP errors
export function createError(status, message) {
  const err = new Error(message)
  err.status = status
  return err
}
```

## Input Validation

```javascript
// src/middleware/validate.js
import { validationResult } from 'express-validator'

export function validate(req, res, next) {
  const errors = validationResult(req)
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() })
  }
  next()
}
```

## Routes with Validation

```javascript
// src/routes/users.js
import { Router } from 'express'
import { body, param } from 'express-validator'
import { validate } from '../middleware/validate.js'
import * as usersController from '../controllers/usersController.js'

const router = Router()

// GET /api/users
router.get('/', usersController.getAll)

// GET /api/users/:id
router.get('/:id',
  param('id').isUUID().withMessage('Invalid user ID'),
  validate,
  usersController.getById
)

// POST /api/users
router.post('/',
  body('email').isEmail().normalizeEmail(),
  body('name').trim().isLength({ min: 2, max: 100 }),
  body('password').isLength({ min: 8 }),
  validate,
  usersController.create
)

export default router
```

## JWT Authentication

```javascript
// src/middleware/auth.js
import jwt from 'jsonwebtoken'
import { createError } from './errorHandler.js'

export function requireAuth(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1]
  if (!token) return next(createError(401, 'No token provided'))

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET)
    next()
  } catch {
    next(createError(401, 'Invalid token'))
  }
}
```

## Async Error Handling

Wrap async route handlers to catch errors automatically:

```javascript
export function asyncHandler(fn) {
  return (req, res, next) => {
    Promise.resolve(fn(req, res, next)).catch(next)
  }
}

// Usage
router.get('/:id', asyncHandler(async (req, res) => {
  const user = await db.users.findById(req.params.id)
  if (!user) throw createError(404, 'User not found')
  res.json(user)
}))
```

## Production Checklist

- Set `NODE_ENV=production` in your environment
- Use `helmet` for security headers (already included above)
- Rate limit your API with `express-rate-limit`
- Log errors to a service like Sentry
- Use a process manager like PM2 for zero-downtime restarts
- Put a reverse proxy (Nginx or Cloudflare) in front of your Node process

This structure scales from a weekend project to a production API serving millions of requests.
